const ASCII_CHARS = "@#S%?*+;:,. "; // плотный → светлый
const mapScale = (ASCII_CHARS.length - 1) / 255;

let bitCanvas, bitCtx;

self.onmessage = async (e) => {
  const { bitmap, width, height, fontSize, isColor } = e.data;

  // 1️⃣ создаём canvas для ASCII
  if (!bitCanvas) {
    bitCanvas = new OffscreenCanvas(width * fontSize, height * fontSize);
    bitCtx = bitCanvas.getContext("2d");
    bitCtx.textBaseline = "top";
    bitCtx.font = `${fontSize}px monospace`;
  }

  bitCanvas.width = width * fontSize;
  bitCanvas.height = height * fontSize;

  bitCtx.fillStyle = "#000";
  bitCtx.fillRect(0, 0, bitCanvas.width, bitCanvas.height);
  bitCtx.font = `${fontSize}px monospace`;
  bitCtx.textBaseline = "top";

  const srcW = bitmap.width;
  const srcH = bitmap.height;

  // 2️⃣ читаем пиксели
  const tmpCanvas = new OffscreenCanvas(srcW, srcH);
  const tmpCtx = tmpCanvas.getContext("2d");
  tmpCtx.drawImage(bitmap, 0, 0);
  const srcData = tmpCtx.getImageData(0, 0, srcW, srcH).data;

  // 3️⃣ пропорции + letterbox
  const dstW = width;
  const dstH = height;
  const srcAspect = srcW / srcH;
  const dstAspect = dstW / dstH;

  let drawCols, drawRows, offsetX, offsetY;

  if (srcAspect > dstAspect) {
    drawCols = dstW;
    drawRows = drawCols / srcAspect;
    offsetX = 0;
    offsetY = (dstH - drawRows) / 2;
  } else {
    drawRows = dstH;
    drawCols = drawRows * srcAspect;
    offsetY = 0;
    offsetX = (dstW - drawCols) / 2;
  }

  drawCols = Math.floor(drawCols);
  drawRows = Math.floor(drawRows);
  offsetX = Math.floor(offsetX);
  offsetY = Math.floor(offsetY);

  // 4️⃣ рендер ASCII
  for (let y = 0; y < dstH; y++) {
    for (let x = 0; x < dstW; x++) {
      let r = 0, g = 0, b = 0;

      // letterbox: внутри картинки
      if (x >= offsetX && x < offsetX + drawCols && y >= offsetY && y < offsetY + drawRows) {
        const u = (x - offsetX) / drawCols;
        const v = (y - offsetY) / drawRows;

        const srcX = Math.min(srcW - 1, Math.floor(u * srcW));
        const srcY = Math.min(srcH - 1, Math.floor(v * srcH));

        const idx = (srcY * srcW + srcX) * 4;
        r = srcData[idx];
        g = srcData[idx + 1];
        b = srcData[idx + 2];
      }

      // яркость
      const brightness = Math.floor((r + g + b) / 3);
      let index = Math.floor(brightness * mapScale);

      // ч/б режим: инвертируем индекс
      if (!isColor) {
        index = (ASCII_CHARS.length - 1) - index;
      }

      const char = ASCII_CHARS[index];

      bitCtx.fillStyle = isColor ? `rgb(${r},${g},${b})` : "#fff";
      bitCtx.fillText(char, x * fontSize, y * fontSize);
    }
  }

  // 5️⃣ отправка bitmap в App.jsx
  const result = bitCanvas.transferToImageBitmap();
  self.postMessage(result, [result]);
};
